1	package bind
2	
3	import (
4		"bytes"
5		"crypto/rand"
6		"net/netip"
7		"testing"
8	
9		"github.com/7mind/wanbond/internal/config"
10		"github.com/7mind/wanbond/internal/fec"
11		"github.com/7mind/wanbond/internal/frame"
12		"github.com/7mind/wanbond/internal/telemetry"
13	)
14	
15	// This file codifies Q27 — the cross-peer isolation threat model — as concrete unit-level
16	// adversary cases against the T83-T91 multi-peer demux machinery. The claim it makes concrete:
17	//
18	//   - A party knowing ONLY peer B's psk can bind/disturb ONLY peer B. It can NEVER move peer A's
19	//     source->peer binding, inject into A's resequencer, or evict A. The isolation rests on two
20	//     production guards plus the frame codec:
21	//       (1) demuxInbound routes an ALREADY-BOUND source to its owner peer's view ONLY (the
22	//           lookupPeerBySource early-return) — a bound source is never re-trial-decoded, so a
23	//           foreign-psk PROBE from it can never re-point the binding.
24	//       (2) The trial-decode loop binds a NEW source ONLY on an authenticated PROBE (the
25	//           `if !isProbe continue` D9/D11 gate) — forged DATA/PARITY floods bind nothing.
26	//     The codec supplies the third leg: PROBE/CONTROL carry an HMAC tag (forging A's tag without
27	//     A's psk is infeasible), and DATA/PARITY are psk-keyed-obfuscated, so a frame built under B's
28	//     psk decodes under A's psk only as UNCONTROLLED garbage (~2/256) — never attacker-CHOSEN
29	//     content. Every assertion below is therefore either fully deterministic or immune to that
30	//     garble by keying on a chosen sentinel payload the wrong-key decode can never reproduce.
31	//
32	//   - A party with NO valid psk is limited to bounded bootstrap degradation: its floods bind
33	//     nothing (no PROBE authenticates), corrupt no peer's stream, and evict no live peer.
34	
35	// victimPeerFEC stands up a FEC-configured concentrator whose PRIMARY (peer A, pskA) is the
36	// isolation VICTIM: a source is bound to it via an authenticated PROBE and its path driven Up
37	// (a LIVE peer that must never be disturbed or evicted). Peer B (pskB) is bound LAZILY (no heavy
38	// state) and stands in for the peer whose psk the adversary holds. FEC is on so the victim carries
39	// an armed decoder whose non-disturbance the FEC-garbage cases can assert. It returns the bind,
40	// both peers, the fake clock, and the victim's bound source address.
41	func victimPeerFEC(t *testing.T, pskA, pskB config.Key) (m *Multipath, victim, peerB *peerState, clk *fakeClock, victimSrc netip.AddrPort) {
42		t.Helper()
43		fecCfg := &fec.Config{DataShards: 4, ParityShards: 1, Deadline: testFECDeadline}
44		m, victim, peerB, clk = lazyConcentratorFEC(t, pskA, pskB, fecCfg)
45	
46		src := synthSource(0)
47		// Bind the victim source to peer A through an authenticated PROBE, then drive its path Up so
48		// A is a genuinely LIVE, bound peer for the duration of every attack below.
49		m.demuxInbound(m.paths[0], authProbe(t, pskA, m.paths[0].id, 1, clk), src)
50		bound, ok := m.lookupPeerBySource(src.Addr())
51		if !ok || bound != victim {
52			t.Fatalf("victim source did not bind to peer A: bound=%v ok=%v", bound, ok)
53		}
54		driveConcentratorPathUp(t, m.paths[0], pskA, clk)
55		if m.paths[0].prober.State() != telemetry.StateUp {
56			t.Fatalf("victim path not Up after drive: %v", m.paths[0].prober.State())
57		}
58		return m, victim, peerB, clk, src
59	}
60	
61	// TestForeignProbeCannotMoveVictimBinding is the centerpiece: a source bound to peer A cannot be
62	// re-pointed, unbound, or otherwise disturbed by frames an adversary crafts under a DIFFERENT psk
63	// (peer B's, or a psk no peer holds). It mutation-discriminates the demuxInbound bound-source
64	// early-return: with that guard removed, the foreign-psk PROBE subtest re-trial-decodes the bound
65	// source and re-points it to peer B, turning the "still bound to A" assertion red.
66	func TestForeignProbeCannotMoveVictimBinding(t *testing.T) {
67		pskA := testKey(t, 0x11) // victim (primary)
68		pskB := testKey(t, 0x22) // the psk the adversary holds
69		pskC := testKey(t, 0x33) // a psk NO peer holds (the no-valid-psk adversary)
70	
71		t.Run("an authenticated PROBE under peer B's psk from A's bound source does NOT re-point the binding", func(t *testing.T) {
72			m, victim, peerB, clk, src := victimPeerFEC(t, pskA, pskB)
73			secondView := peerPathByName(peerB, "a")
74	
75			// The adversary holds pskB and forges a valid, authenticated PROBE from the victim's own
76			// bound source address. It authenticates under B's psk — but the source is already bound to
77			// A, so demuxInbound routes it to A's view, where A's codec cannot decode a B-authenticated
78			// frame. It must NOT reach the trial-decode loop that would re-bind it to B.
79			m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 2, clk), src)
80	
81			// The binding is unmoved: still A, never re-pointed to B (the T90 roam path must never fire
82			// for a foreign-psk frame). With the early-return removed this reads peer B.
83			bound, ok := m.lookupPeerBySource(src.Addr())
84			if !ok || bound != victim {
85				t.Fatalf("foreign-psk PROBE re-pointed A's bound source: bound=%v ok=%v (want peer A)", bound, ok)
86			}
87			// Peer B was never consulted: it learned no remote on its view and its lazy heavy state was
88			// never instantiated (a re-point would have called ensurePeerReceiveInstantiated on B).
89			if _, ok := secondView.getRemote(); ok {
90				t.Fatal("peer B learned a remote from a PROBE aimed at A's bound source")
91			}
92			if peerB.resequencer.Load() != nil {
93				t.Fatal("peer B's heavy receive state was instantiated by a foreign PROBE (it was re-bound)")
94			}
95			if peerB.fecRecv.Load() != nil {
96				t.Fatal("peer B's FEC decoder was instantiated by a foreign PROBE")
97			}
98			// The victim was untouched: still Up (not evicted).
99			if m.paths[0].prober.State() != telemetry.StateUp {
100				t.Fatalf("victim liveness disturbed by a foreign PROBE: %v", m.paths[0].prober.State())
101			}
102		})
103	
104		t.Run("a PROBE under a psk NO peer holds neither re-binds nor unbinds A's bound source", func(t *testing.T) {
105			m, victim, _, clk, src := victimPeerFEC(t, pskA, pskB)
106	
107			// The no-valid-psk adversary forges a PROBE under pskC. Routed to A's view, it fails A's MAC;
108			// it must be a per-frame drop that leaves the binding EXACTLY as it was — neither re-pointed
109			// (no peer holds pskC) NOR unbound (a decode failure must not evict a live binding).
110			m.demuxInbound(m.paths[0], authProbe(t, pskC, m.paths[0].id, 2, clk), src)
111	
112			bound, ok := m.lookupPeerBySource(src.Addr())
113			if !ok {
114				t.Fatal("a wrong-psk PROBE UNBOUND A's live source (a decode failure must never evict a binding)")
115			}
116			if bound != victim {
117				t.Fatalf("a wrong-psk PROBE re-pointed A's source to %v", bound)
118			}
119			if m.paths[0].prober.State() != telemetry.StateUp {
120				t.Fatalf("victim liveness disturbed by a wrong-psk PROBE: %v", m.paths[0].prober.State())
121			}
122		})
123	
124		t.Run("replayed and byte-mutated genuine PROBEs from the bound source do not disturb the binding", func(t *testing.T) {
125			m, victim, _, clk, src := victimPeerFEC(t, pskA, pskB)
126	
127			// A REPLAY of a genuine, authenticated pskA PROBE from the bound source: it decodes cleanly
128			// under A's psk and is reflected, but carries no fresh binding authority — the source is
129			// already bound to A, so the binding is a no-op and stays put.
130			genuine := authProbe(t, pskA, m.paths[0].id, 2, clk)
131			m.demuxInbound(m.paths[0], genuine, src)
132			if bound, ok := m.lookupPeerBySource(src.Addr()); !ok || bound != victim {
133				t.Fatalf("a replayed genuine PROBE disturbed A's binding: bound=%v ok=%v", bound, ok)
134			}
135	
136			// A byte-MUTATED genuine PROBE: flipping a body byte breaks A's MAC (or garbles the kind),
137			// so A's codec rejects it — a per-frame drop that leaves the binding untouched.
138			mutated := append([]byte(nil), genuine...)
139			mutated[len(mutated)-1] ^= 0xFF // corrupt the authentication tag
140			m.demuxInbound(m.paths[0], mutated, src)
141			if bound, ok := m.lookupPeerBySource(src.Addr()); !ok || bound != victim {
142				t.Fatalf("a mutated PROBE disturbed A's binding: bound=%v ok=%v", bound, ok)
143			}
144			if m.paths[0].prober.State() != telemetry.StateUp {
145				t.Fatalf("victim liveness disturbed by replay/mutation: %v", m.paths[0].prober.State())
146			}
147		})
148	
149		t.Run("a forged DATA storm under B's psk from A's bound source injects no chosen content and moves no release point", func(t *testing.T) {
150			m, victim, peerB, _, src := victimPeerFEC(t, pskA, pskB)
151			secondView := peerPathByName(peerB, "a")
152			codecA, err := frame.NewCodec(pskA)
153			if err != nil {
154				t.Fatalf("build peer A codec: %v", err)
155			}
156			codecB, err := frame.NewCodec(pskB)
157			if err != nil {
158				t.Fatalf("build peer B codec: %v", err)
159			}
160	
161			// Establish A's release point at 100 (deliver one legit frame, advancing `next` to 101).
162			m.demuxInbound(m.paths[0], mustEncodeData(t, codecA, 100, m.paths[0].id, "v100"), src)
163			if it, ok := victim.resequencer.Load().Pop(); !ok || string(it.Payload) != "v100" {
164				t.Fatalf("victim did not deliver its legit frame: ok=%v payload=%q", ok, it.Payload)
165			}
166	
167			// The adversary (holding pskB) floods DATA authenticated under B's psk from the victim's own
168			// bound source, carrying a CHOSEN sentinel payload and wildly discontinuous outer-seqs (the
169			// outer-seq-discontinuity storm). Routed to A's view, each frame fails A's psk-keyed decode
170			// and is dropped; the ~2/256 that garble-decode carry UNCONTROLLED bytes, never the sentinel.
171			const sentinel = "FORGED-BY-B"
172			wildSeqs := []uint64{1, 1 << 20, 1 << 40, 1 << 62, 0xFFFFFFFFFFFFFFFF, 202, 5000}
173			const floodPerSeq = 40
174			for _, seq := range wildSeqs {
175				for i := 0; i < floodPerSeq; i++ {
176					m.demuxInbound(m.paths[0], mustEncodeData(t, codecB, seq, secondView.id, sentinel), src)
177				}
178			}
179	
180			// The binding and liveness are intact (no eviction), and peer B — whose psk the adversary
181			// holds — got NO binding to A's source (the storm cannot bleed A's source into B).
182			if bound, ok := m.lookupPeerBySource(src.Addr()); !ok || bound != victim {
183				t.Fatalf("the forged storm disturbed A's binding: bound=%v ok=%v", bound, ok)
184			}
185			if m.paths[0].prober.State() != telemetry.StateUp {
186				t.Fatalf("the forged storm evicted/disturbed the live victim: %v", m.paths[0].prober.State())
187			}
188	
189			// The stream still flows AND its release point never moved: a legit pskA frame at the very
190			// NEXT outer-seq (101) delivers immediately. A storm that had dragged A's release point
191			// forward (to one of the wild high seqs) would reject 101 as late and deliver nothing here.
192			m.demuxInbound(m.paths[0], mustEncodeData(t, codecA, 101, m.paths[0].id, "v101"), src)
193			var delivered []string
194			for {
195				it, ok := victim.resequencer.Load().Pop()
196				if !ok {
197					break
198				}
199				delivered = append(delivered, string(it.Payload))
200			}
201			sawNext := false
202			for _, p := range delivered {
203				if p == sentinel {
204					t.Fatalf("the adversary's CHOSEN payload %q was delivered up the victim's stream", sentinel)
205				}
206				if p == "v101" {
207					sawNext = true
208				}
209			}
210			if !sawNext {
211				t.Fatalf("the victim's release point was moved by the storm: legit seq 101 was not delivered (got %v)", delivered)
212			}
213		})
214	}
215	
216	// TestUnauthenticatedFloodBindsNothingAndInjectsNothing is the no-valid-psk / wrong-psk flood
217	// case: a flood of DATA/PARITY (forged under peer B's psk) and pure garbage from MANY distinct,
218	// unbound spoofed sources binds nothing (no PROBE authenticates), grows no demux state, injects
219	// into NO peer's resequencer or FEC decoder, and never disturbs the live victim binding. It
220	// mutation-discriminates the trial-decode `if !isProbe continue` D9/D11 gate: with that gate
221	// removed, a DATA/PARITY that decodes under peer B's view binds its source to B and dispatches
222	// into B's planes, turning the "no binding grew / decoder untouched" assertions red.
223	func TestUnauthenticatedFloodBindsNothingAndInjectsNothing(t *testing.T) {
224		pskA := testKey(t, 0x11)
225		pskB := testKey(t, 0x22)
226		m, victim, peerB, _, victimSrc := victimPeerFEC(t, pskA, pskB)
227		secondView := peerPathByName(peerB, "a")
228		fecCfg := fec.Config{DataShards: 4, ParityShards: 1, Deadline: testFECDeadline}
229		codecB, err := frame.NewCodec(pskB)
230		if err != nil {
231			t.Fatalf("build peer B codec: %v", err)
232		}
233	
234		// Buffer a known frame in the victim's ring (not yet popped): the flood must leave it intact.
235		codecA, err := frame.NewCodec(pskA)
236		if err != nil {
237			t.Fatalf("build peer A codec: %v", err)
238		}
239		m.demuxInbound(m.paths[0], mustEncodeData(t, codecA, 500, m.paths[0].id, "victim-buffered"), victimSrc)
240	
241		before := m.peerBySourceLenForTest()
242		victimDecoderRecoveredBefore := victim.fecRecv.Load().stats().Recovered
243	
244		// The flood: from 300 distinct spoofed unbound sources, cycle three adversary shapes —
245		// DATA forged under B's psk, a single-frame reconstructing PARITY forged under B's psk (FEC
246		// garbage that WOULD reconstruct a data frame if it ever reached a decoder), and pure random
247		// garbage (the no-psk adversary). None is an authenticated PROBE, so none may bind.
248		const flood = 300
249		for i := 1; i <= flood; i++ {
250			src := synthSource(i)
251			switch i % 3 {
252			case 0:
253				m.demuxInbound(m.paths[0], mustEncodeData(t, codecB, uint64(i), secondView.id, "flood-data"), src)
254			case 1:
255				group, index, dataCount, parityPayload := singleFrameParity(t, fecCfg, uint64(1000+i), []byte("flood-parity"))
256				parity, perr := codecB.Encode(nil, frame.Parity{FECGroup: group, ParityIndex: index, DataCount: dataCount, PathID: secondView.id, Payload: parityPayload})
257				if perr != nil {
258					t.Fatalf("encode flood parity: %v", perr)
259				}
260				m.demuxInbound(m.paths[0], parity, src)
261			default:
262				garbage := make([]byte, 96)
263				if _, rerr := rand.Read(garbage); rerr != nil {
264					t.Fatalf("draw garbage: %v", rerr)
265				}
266				m.demuxInbound(m.paths[0], garbage, src)
267			}
268		}
269	
270		// No source bound: the demux map did not grow by a single entry (bootstrap flood is bounded).
271		if after := m.peerBySourceLenForTest(); after != before {
272			t.Fatalf("the unauthenticated flood grew the demux map from %d to %d (a non-PROBE bound a source)", before, after)
273		}
274		// Peer B — whose psk half the flood used — was never bound or instantiated: its lazy heavy
275		// state is still absent (a DATA/PARITY that decoded under B's view must never bind B).
276		if peerB.resequencer.Load() != nil {
277			t.Fatal("peer B's heavy state was instantiated by a non-PROBE flood (a DATA/PARITY bound it)")
278		}
279		if _, ok := secondView.getRemote(); ok {
280			t.Fatal("peer B learned a remote from a non-PROBE flood")
281		}
282		// The victim's armed FEC decoder never advanced: no flood PARITY reached it (a leaked PARITY
283		// with DataCount=1 would have reconstructed a frame and moved Recovered).
284		if got := victim.fecRecv.Load().stats().Recovered; got != victimDecoderRecoveredBefore {
285			t.Fatalf("the flood's FEC garbage reached the victim's decoder: Recovered %d -> %d", victimDecoderRecoveredBefore, got)
286		}
287		// The live victim binding, liveness, and buffered frame all survived untouched.
288		if bound, ok := m.lookupPeerBySource(victimSrc.Addr()); !ok || bound != victim {
289			t.Fatal("the flood disturbed the live victim binding")
290		}
291		if m.paths[0].prober.State() != telemetry.StateUp {
292			t.Fatalf("the flood evicted/disturbed the live victim: %v", m.paths[0].prober.State())
293		}
294		if it, ok := victim.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("victim-buffered")) {
295			t.Fatalf("the flood corrupted the victim's buffered frame: ok=%v payload=%q", ok, it.Payload)
296		}
297	}
